  cr_rep UUID := (SELECT id FROM cash_registers WHERE type = 'repairs');
  sf_opex UUID := (SELECT id FROM safes WHERE type = 'opex');
  sf_growth UUID := (SELECT id FROM safes WHERE type = 'growth');
  sf_profit UUID := (SELECT id FROM safes WHERE type = 'net_profit');
BEGIN
    -- Sale payments into cash registers
    ('trn00001-0000-0000-0000-000000000001', 38500, 'customer', 'cash_register', cr_tech, 'sale', 'sal00001-0000-0000-0000-000000000001', 'iPhone 15 Pro — Олена К.', 'p0000000-0000-0000-0000-000000000001'),
